   121→/// Output structure for saddle command
   122→#[derive(Serialize)]
   123→pub(crate) struct zjjrq_SaddleOutput {
   124→    pub(crate) heat_silks: String,
   125→    pub(crate) paddock_file: String,
   126→    pub(crate) paddock_content: String,
   127→    #[serde(skip_serializing_if = "Option::is_none")]
   128→    pub(crate) pace_coronet: Option<String>,
   129→    #[serde(skip_serializing_if = "Option::is_none")]
   130→    pub(crate) pace_silks: Option<String>,
   131→    #[serde(skip_serializing_if = "Option::is_none")]
   132→    pub(crate) pace_state: Option<String>,
   133→    #[serde(skip_serializing_if = "Option::is_none")]
   134→    pub(crate) spec: Option<String>,
   135→    #[serde(skip_serializing_if = "Option::is_none")]
   136→    pub(crate) direction: Option<String>,
