   140→/// Run the saddle command - return Heat context
   141→pub fn jjrq_run_saddle(args: jjrq_SaddleArgs) -> i32 {
   142→    let gallops = match Gallops::jjrg_load(&args.file) {
   143→        Ok(g) => g,
   144→        Err(e) => {
   145→            eprintln!("jjx_saddle: error: {}", e);
   146→            return 1;
   147→        }
   148→    };
   149→
   150→    let heat_key = args.firemark.jjrf_display();
   151→    let heat = match gallops.heats.get(&heat_key) {
   152→        Some(h) => h,
   153→        None => {
   154→            eprintln!("jjx_saddle: error: Heat '{}' not found", heat_key);
   155→            return 1;
   156→        }
   157→    };
   158→
   159→    // Check if heat is stabled (cannot saddle stabled heat)
   160→    if heat.status == HeatStatus::Stabled {
   161→        eprintln!("jjx_saddle: error: Cannot saddle stabled heat '{}'", heat_key);
   162→        return 1;
   163→    }
   164→
   165→    // Read paddock file content
   166→    let paddock_content = match fs::read_to_string(&heat.paddock_file) {
   167→        Ok(content) => content,
   168→        Err(e) => {
   169→            eprintln!("jjx_saddle: error reading paddock file '{}': {}", heat.paddock_file, e);
   170→            return 1;
   171→        }
   172→    };
   173→
   174→    // Get recent steeplechase entries
   175→    let recent_work = jjrs_get_entries(&jjrs_ReinArgs {
   176→        firemark: args.firemark.jjrf_as_str().to_string(),
   177→        limit: 10,
   178→    }).unwrap_or_default();
   179→
   180→    // Find first actionable pace (rough or bridled)
   181→    let mut output = zjjrq_SaddleOutput {
   182→        heat_silks: heat.silks.clone(),
   183→        paddock_file: heat.paddock_file.clone(),
   184→        paddock_content,
   185→        pace_coronet: None,
   186→        pace_silks: None,
   187→        pace_state: None,
   188→        spec: None,
   189→        direction: None,
   190→        recent_work,
   191→    };
   192→
   193→    for coronet_key in &heat.order {
   194→        if let Some(pace) = heat.paces.get(coronet_key) {
   195→            if let Some(tack) = pace.tacks.first() {
   196→                match tack.state {
   197→                    PaceState::Rough | PaceState::Bridled => {
   198→                        output.pace_coronet = Some(coronet_key.clone());
   199→                        output.pace_silks = Some(tack.silks.clone());
   200→                        output.pace_state = Some(match tack.state {
   201→                            PaceState::Rough => "rough".to_string(),
   202→                            PaceState::Bridled => "bridled".to_string(),
   203→                            _ => unreachable!(),
   204→                        });
   205→                        output.spec = Some(tack.text.clone());
   206→                        if tack.state == PaceState::Bridled {
   207→                            output.direction = tack.direction.clone();
   208→                        }
   209→                        break;
   210→                    }
   211→                    _ => continue,
   212→                }
   213→            }
   214→        }
   215→    }
   216→
   217→    // Output JSON
   218→    match serde_json::to_string_pretty(&output) {
   219→        Ok(json) => {
   220→            println!("{}", json);
   221→            0
   222→        }
   223→        Err(e) => {
   224→            eprintln!("jjx_saddle: error serializing output: {}", e);
   225→            1
   226→        }
   227→    }
   228→}
