   234→/// Arguments for parade command
   235→#[derive(Debug)]
   236→pub struct jjrq_ParadeArgs {
   237→    pub file: std::path::PathBuf,
   238→    pub target: String,
   239→    pub full: bool,
   240→    pub remaining: bool,
   241→}
   242→
   243→/// Run the parade command - display comprehensive Heat status
   244→pub fn jjrq_run_parade(args: jjrq_ParadeArgs) -> i32 {
   245→    let gallops = match Gallops::jjrg_load(&args.file) {
   246→        Ok(g) => g,
   247→        Err(e) => {
   248→            eprintln!("jjx_parade: error: {}", e);
   249→            return 1;
   250→        }
   251→    };
   252→
   253→    // Determine target type by length
   254→    let target_str = args.target.strip_prefix('₢').or_else(|| args.target.strip_prefix('₣')).unwrap_or(&args.target);
   255→
   256→    if target_str.len() == 5 {
   257→        // Coronet - pace view
   258→        let coronet = match Coronet::jjrf_parse(&args.target) {
   259→            Ok(c) => c,
   260→            Err(e) => {
   261→                eprintln!("jjx_parade: error: {}", e);
   262→                return 1;
   263→            }
   264→        };
   265→
   266→        // Extract parent firemark
   267→        let firemark = coronet.jjrf_parent_firemark();
   268→        let heat_key = firemark.jjrf_display();
   269→        let heat = match gallops.heats.get(&heat_key) {
   270→            Some(h) => h,
   271→            None => {
   272→                eprintln!("jjx_parade: error: Heat '{}' not found", heat_key);
   273→                return 1;
   274→            }
   275→        };
   276→
   277→        // Find pace
   278→        let coronet_key = coronet.jjrf_display();
   279→        let pace = match heat.paces.get(&coronet_key) {
   280→            Some(p) => p,
   281→            None => {
   282→                eprintln!("jjx_parade: error: Pace '{}' not found in Heat '{}'", coronet_key, heat_key);
   283→                return 1;
   284→            }
   285→        };
   286→
   287→        // Display tack history - iterate in reverse order (oldest first)
   288→        if !pace.tacks.is_empty() {
   289→            // Print header with current state from tacks[0]
   290→            let current_tack = &pace.tacks[0];
   291→            println!("Pace: {} ({})", current_tack.silks, coronet_key);
   292→            println!("Heat: {}", heat_key);
   293→            println!();
   294→
   295→            // Iterate tacks in reverse order (oldest first)
   296→            for (index, tack) in pace.tacks.iter().rev().enumerate() {
   297→                let state_str = zjjrq_pace_state_str(&tack.state);
   298→                let commit_str = if tack.commit == "0000000" {
   299→                    "(no commit)".to_string()
   300→                } else {
   301→                    tack.commit.clone()
   302→                };
   303→
   304→                println!("[{}] {} ({})", index, state_str, commit_str);
   305→                println!("    Silks: {}", tack.silks);
   306→                if let Some(ref direction) = tack.direction {
   307→                    println!("    Direction: {}", direction);
   308→                }
   309→                println!();
   310→                // Indent spec text
   311→                for line in tack.text.lines() {
   312→                    println!("    {}", line);
   313→                }
   314→                println!();
   315→            }
   316→        }
   317→    } else if target_str.len() == 2 {
   318→        // Firemark - heat view
   319→        let firemark = match Firemark::jjrf_parse(&args.target) {
   320→            Ok(fm) => fm,
   321→            Err(e) => {
   322→                eprintln!("jjx_parade: error: {}", e);
   323→                return 1;
   324→            }
   325→        };
   326→
   327→        let heat_key = firemark.jjrf_display();
   328→        let heat = match gallops.heats.get(&heat_key) {
   329→            Some(h) => h,
   330→            None => {
   331→                eprintln!("jjx_parade: error: Heat '{}' not found", heat_key);
   332→                return 1;
   333→            }
   334→        };
   335→
   336→        if args.full {
   337→            // Full view: paddock + all specs
   338→            let paddock_content = match fs::read_to_string(&heat.paddock_file) {
   339→                Ok(content) => content,
   340→                Err(e) => {
   341→                    eprintln!("jjx_parade: error reading paddock file '{}': {}", heat.paddock_file, e);
   342→                    return 1;
   343→                }
   344→            };
   345→
   346→            let status_str = match heat.status {
   347→                HeatStatus::Racing => "racing",
   348→                HeatStatus::Stabled => "stabled",
   349→                HeatStatus::Retired => "retired",
   350→            };
   351→
   352→            println!("Heat: {} ({})", heat.silks, heat_key);
   353→            println!("Status: {}", status_str);
   354→            println!("Created: {}", heat.creation_time);
   355→            println!();
   356→            println!("## Paddock");
   357→            println!();
   358→            println!("{}", paddock_content);
   359→            println!();
   360→            println!("## Paces");
   361→            println!();
   362→
   363→            for coronet_key in &heat.order {
   364→                if let Some(pace) = heat.paces.get(coronet_key) {
   365→                    if let Some(tack) = pace.tacks.first() {
   366→                        // Skip complete/abandoned if --remaining
   367→                        if args.remaining && (tack.state == PaceState::Complete || tack.state == PaceState::Abandoned) {
   368→                            continue;
   369→                        }
   370→                        let state_str = zjjrq_pace_state_str(&tack.state);
   371→                        println!("### {} ({}) [{}]", tack.silks, coronet_key, state_str);
   372→                        println!();
   373→                        println!("{}", tack.text);
   374→                        if let Some(ref direction) = tack.direction {
   375→                            println!();
   376→                            println!("**Direction:** {}", direction);
   377→                        }
   378→                        println!();
   379→                    }
   380→                }
   381→            }
   382→        } else {
   383→            // List view: numbered paces
   384→            // If --remaining, compute and print progress stats first
   385→            if args.remaining {
   386→                let mut complete_count = 0;
   387→                let mut abandoned_count = 0;
   388→                let mut rough_count = 0;
   389→                let mut bridled_count = 0;
   390→                for coronet_key in &heat.order {
   391→                    if let Some(pace) = heat.paces.get(coronet_key) {
   392→                        if let Some(tack) = pace.tacks.first() {
   393→                            match tack.state {
   394→                                PaceState::Complete => complete_count += 1,
   395→                                PaceState::Abandoned => abandoned_count += 1,
   396→                                PaceState::Rough => rough_count += 1,
   397→                                PaceState::Bridled => bridled_count += 1,
   398→                            }
   399→                        }
   400→                    }
   401→                }
   402→                let remaining_count = rough_count + bridled_count;
   403→                println!("# Progress: {} complete, {} abandoned, {} remaining ({} rough, {} bridled)",
   404→                    complete_count, abandoned_count, remaining_count, rough_count, bridled_count);
   405→            }
   406→
   407→            let mut num = 0;
   408→            for coronet_key in &heat.order {
   409→                if let Some(pace) = heat.paces.get(coronet_key) {
   410→                    if let Some(tack) = pace.tacks.first() {
   411→                        // Skip complete/abandoned if --remaining
   412→                        if args.remaining && (tack.state == PaceState::Complete || tack.state == PaceState::Abandoned) {
   413→                            continue;
   414→                        }
   415→                        num += 1;
   416→                        let state_str = zjjrq_pace_state_str(&tack.state);
   417→                        println!("{}. [{}] {} ({})", num, state_str, tack.silks, coronet_key);
   418→                    }
   419→                }
   420→            }
   421→        }
   422→    } else {
   423→        eprintln!("jjx_parade: error: target must be Firemark (2 chars) or Coronet (5 chars), got {} chars", target_str.len());
   424→        return 1;
   425→    }
   426→
   427→    0
   428→}
   429→
   430→/// Helper to convert PaceState to display string
   431→fn zjjrq_pace_state_str(state: &PaceState) -> &'static str {
   432→    match state {
   433→        PaceState::Rough => "rough",
   434→        PaceState::Bridled => "bridled",
   435→        PaceState::Complete => "complete",
   436→        PaceState::Abandoned => "abandoned",
   437→    }
   438→}
