   440→// ============================================================================
   441→// Scout - Search across heats and paces with regex
   442→// ============================================================================
   443→
   444→/// Arguments for scout command
   445→#[derive(Debug)]
   446→pub struct jjrq_ScoutArgs {
   447→    pub file: std::path::PathBuf,
   448→    pub pattern: String,
   449→    pub actionable: bool,
   450→}
   451→
   452→/// Run the scout command - regex search across heats/paces
   453→pub fn jjrq_run_scout(args: jjrq_ScoutArgs) -> i32 {
   454→    use regex::RegexBuilder;
   455→
   456→    let gallops = match Gallops::jjrg_load(&args.file) {
   457→        Ok(g) => g,
   458→        Err(e) => {
   459→            eprintln!("jjx_scout: error: {}", e);
   460→            return 1;
   461→        }
   462→    };
   463→
   464→    // Build case-insensitive regex
   465→    let re = match RegexBuilder::new(&args.pattern)
   466→        .case_insensitive(true)
   467→        .build()
   468→    {
   469→        Ok(r) => r,
   470→        Err(e) => {
   471→            eprintln!("jjx_scout: error: invalid regex pattern: {}", e);
   472→            return 1;
   473→        }
   474→    };
   475→
   476→    // Track which heats have matches (for group headers)
   477→    let mut current_heat_key: Option<String> = None;
   478→
   479→    // Iterate all heats (racing, stabled, retired)
   480→    for (heat_key, heat) in &gallops.heats {
   481→        // Search each pace in order
   482→        for coronet_key in &heat.order {
   483→            if let Some(pace) = heat.paces.get(coronet_key) {
   484→                if let Some(tack) = pace.tacks.first() {
   485→                    // Apply actionable filter if requested
   486→                    if args.actionable {
   487→                        match tack.state {
   488→                            PaceState::Rough | PaceState::Bridled => {},
   489→                            _ => continue,
   490→                        }
   491→                    }
   492→
   493→                    // Search: silks, spec (tack text), direction, paddock content
   494→                    // Use owned strings to avoid lifetime issues
   495→                    let mut match_result: Option<(String, String)> = None;
   496→
   497→                    if re.is_match(&tack.silks) {
   498→                        match_result = Some(("silks".to_string(), tack.silks.clone()));
   499→                    } else if re.is_match(&tack.text) {
   500→                        match_result = Some(("spec".to_string(), tack.text.clone()));
   501→                    } else if let Some(ref direction) = tack.direction {
   502→                        if re.is_match(direction) {
   503→                            match_result = Some(("direction".to_string(), direction.clone()));
   504→                        }
   505→                    } else {
   506→                        // Search paddock content
   507→                        let paddock_path = std::path::Path::new(&heat.paddock_file);
   508→                        if let Ok(content) = fs::read_to_string(paddock_path) {
   509→                            if re.is_match(&content) {
   510→                                match_result = Some(("paddock".to_string(), content));
   511→                            }
   512→                        }
   513→                    }
   514→
   515→                    // If we found a match, output it
   516→                    if let Some((field_name, field_content)) = match_result {
   517→                        // Print heat header if this is a new heat
   518→                        if current_heat_key.as_ref() != Some(heat_key) {
   519→                            println!("{} {}", heat_key, heat.silks);
   520→                            current_heat_key = Some(heat_key.clone());
   521→                        }
   522→
   523→                        // Print pace line
   524→                        let state_str = zjjrq_pace_state_str(&tack.state);
   525→                        println!("  {} [{}] {}", coronet_key, state_str, tack.silks);
   526→
   527→                        // Print match line with context (extract ~60 chars around match)
   528→                        let match_excerpt = zjjrq_extract_match_context(&field_content, &re);
   529→                        println!("    {}: {}", field_name, match_excerpt);
   530→                    }
   531→                }
   532→            }
   533→        }
   534→    }
   535→
   536→    0
   537→}
   538→
   539→/// Extract context around the first regex match in content
   540→fn zjjrq_extract_match_context(content: &str, re: &regex::Regex) -> String {
   541→    if let Some(mat) = re.find(content) {
   542→        let start = mat.start();
   543→        let end = mat.end();
   544→
   545→        // Find context window (30 chars before, 30 chars after)
   546→        let context_before = 30;
   547→        let context_after = 30;
   548→
   549→        let window_start = start.saturating_sub(context_before);
   550→        let window_end = (end + context_after).min(content.len());
   551→
   552→        let mut excerpt = String::new();
   553→        if window_start > 0 {
   554→            excerpt.push_str("...");
   555→        }
   556→        excerpt.push_str(&content[window_start..window_end]);
   557→        if window_end < content.len() {
   558→            excerpt.push_str("...");
   559→        }
   560→
   561→        // Replace newlines with spaces for single-line display
   562→        excerpt.replace('\n', " ").replace('\r', "")
   563→    } else {
   564→        // Shouldn't happen, but fallback to truncated content
   565→        let truncated = content.chars().take(60).collect::<String>();
   566→        if content.len() > 60 {
   567→            format!("{}...", truncated)
   568→        } else {
   569→            truncated
   570→        }
   571→    }
   572→}
